// Build a weighted profile object from raw Apify data.
// Title gets 3x weight, skills 2x, bio/description 1x, category 1.5x.
// Each section is kept separate so downstream scoring can weight them.

const items = $input.all();

return items.map((item, idx) => {
  const p = item.json;

  const title    = (p.title || p.professionalTitle || '').trim();
  const bio      = (p.description || p.overview || p.bio || '').trim();
  const category = [p.category || '', p.subcategory || ''].filter(Boolean).join(' ').trim();

  const skills = Array.isArray(p.skills)
    ? p.skills.map(s => (typeof s === 'string' ? s : s.name || '')).join(' ').trim()
    : '';

  const certs = Array.isArray(p.certifications)
    ? p.certifications.map(c => (typeof c === 'string' ? c : c.name || '')).join(' ')
    : '';

  // Weighted concatenation: repeat high-signal fields
  const weightedText = [
    title, title, title,           // 3x
    skills, skills,                // 2x
    category, category,            // 1.5x (rounded to 2)
    bio,                           // 1x
    certs                          // 1x
  ].join(' ').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();

  return {
    json: {
      profileIndex: idx + 1,
      name: p.name || p.fullName || 'Profile ' + (idx + 1),
      titleText: title.toLowerCase(),
      skillsText: skills.toLowerCase(),
      bioText: bio.toLowerCase(),
      weightedText,
      wordCount: weightedText.split(' ').filter(Boolean).length
    }
  };
});

// Coverage-based keyword scoring using document frequency.
// Tracks how many individual profiles contain each keyword (coverage),
// not just how many times it appears in total.
// Produces unigrams, bigrams, and trigrams.

const STOPWORDS = new Set([
  // pronouns & articles
  'i','me','my','we','our','you','your','he','him','his','she','her','it','its',
  'they','them','their','this','that','these','those','a','an','the',
  // verbs
  'am','is','are','was','were','be','been','being','have','has','had','do','does',
  'did','get','got','getting','make','made','making','use','used','using',
  'need','needs','help','helped','helping','work','worked','working',
  'can','will','just','should','would','could','may','might','shall',
  // conjunctions / prepositions / adverbs
  'and','but','if','or','as','of','at','by','for','with','about','into',
  'through','before','after','above','below','to','from','up','down','in',
  'out','on','off','over','under','then','here','there','when','where',
  'how','all','both','each','more','most','some','no','not','only','same',
  'so','than','too','very','also','well','good','great','new','time','now',
  // contractions / fragments
  've','re','ll','don','didn','won','m','s','t','d',
  // filler words common in profiles
  'over','years','year','plus','amp','etc','including','various','many',
  'across','within','along','around','based','per','since','while','such'
]);

const MIN_WORD_LEN = 3;
const MIN_PROFILE_COVERAGE = 2; // keyword must appear in at least 2 profiles

const profiles = $input.all();
const totalProfiles = profiles.length;

// tokenise a single profile text into clean words
function tokenise(text) {
  return (text || '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .split(' ')
    .filter(w => w.length >= MIN_WORD_LEN && !STOPWORDS.has(w));
}

// per-keyword: { totalOccurrences, profilesContaining (Set of profile indices) }
const stats = {};

function record(ngram, profileIdx, occurrences) {
  if (!stats[ngram]) stats[ngram] = { total: 0, profiles: new Set() };
  stats[ngram].total += occurrences;
  stats[ngram].profiles.add(profileIdx);
}

for (let i = 0; i < profiles.length; i++) {
  const words = tokenise(profiles[i].json.weightedText || '');

  // unigrams
  const uniCounts = {};
  for (const w of words) {
    uniCounts[w] = (uniCounts[w] || 0) + 1;
  }
  for (const [w, cnt] of Object.entries(uniCounts)) {
    record(w, i, cnt);
  }

  // bigrams
  const biCounts = {};
  for (let j = 0; j < words.length - 1; j++) {
    const bg = words[j] + ' ' + words[j + 1];
    biCounts[bg] = (biCounts[bg] || 0) + 1;
  }
  for (const [bg, cnt] of Object.entries(biCounts)) {
    record(bg, i, cnt);
  }

  // trigrams
  const triCounts = {};
  for (let j = 0; j < words.length - 2; j++) {
    const tg = words[j] + ' ' + words[j + 1] + ' ' + words[j + 2];
    triCounts[tg] = (triCounts[tg] || 0) + 1;
  }
  for (const [tg, cnt] of Object.entries(triCounts)) {
    record(tg, i, cnt);
  }
}

// build scored list
const results = [];
for (const [kw, data] of Object.entries(stats)) {
  const profileCount = data.profiles.size;
  if (profileCount < MIN_PROFILE_COVERAGE) continue;

  const wordCount = kw.split(' ').length;
  const ngramType = wordCount === 1 ? 'Single Word' : wordCount === 2 ? '2-Word Phrase' : '3-Word Phrase';
  const coveragePct = +((profileCount / totalProfiles) * 100).toFixed(1);

  // composite score: coverage drives rank, total occurrences break ties
  const score = +(coveragePct * 0.7 + (data.total / totalProfiles) * 0.3).toFixed(3);

  results.push({ keyword: kw, ngramType, profileCount, totalProfiles, coveragePct, occurrences: data.total, score });
}

results.sort((a, b) => b.score - a.score);

return results.map(r => ({ json: r }));

// Assign coverage-based tiers and placement advice.
// Tiers reflect how commonly a keyword appears across profiles
// rather than arbitrary rank cutoffs.

const items = $input.all();

return items.map((item, index) => {
  const { keyword, ngramType, profileCount, totalProfiles, coveragePct, occurrences, score } = item.json;

  let tier;
  if (coveragePct >= 50)      tier = 'Essential';
  else if (coveragePct >= 25) tier = 'High Demand';
  else if (coveragePct >= 10) tier = 'Targeted';
  else                        tier = 'Niche';

  const isPhrase = ngramType !== 'Single Word';
  let placement;
  if (coveragePct >= 50)      placement = isPhrase ? 'Profile title + overview intro' : 'Profile title + skills list';
  else if (coveragePct >= 25) placement = isPhrase ? 'Overview paragraph + portfolio tags' : 'Skills list + overview';
  else if (coveragePct >= 10) placement = 'Overview body + specialisation section';
  else                        placement = 'Niche section or portfolio descriptions';

  return {
    json: {
      rank:          index + 1,
      keyword,
      ngramType,
      profilesCoverage: profileCount + ' / ' + totalProfiles,
      coveragePct:   coveragePct + '%',
      occurrences,
      compositeScore: score,
      tier,
      placement
    }
  };
});
